+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: number | 'fr'};
+
+type Placement = {start: number; end: number};
+
+const splitTracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+
+	const tokens = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.map(token => {
+		if (token === 'auto') return {type: 'auto'};
+		const fr = /^(\\d*\\.?\\d+)fr$/.exec(token);
+		if (fr) return {type: 'fr', value: Number(fr[1])};
+		const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(?:(\\d*\\.?\\d+)fr|(\\d*\\.?\\d+))\\s*\\)$/.exec(token);
+		if (minmax) {
+			return {
+				type: 'minmax',
+				min: Number(minmax[1]),
+				max: minmax[2] ? 'fr' : Number(minmax[3]),
+			};
+		}
+
+		const value = Number(token);
+		return Number.isFinite(value) ? {type: 'fixed', value} : {type: 'auto'};
+	});
+};
+
+const placement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number' && value > 0) return {start: value - 1, end: value};
+	if (typeof value !== 'string') return;
+	const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+	if (!match) return;
+	const start = Number(match[1]) - 1;
+	const end = Number(match[2]) - 1;
+	return start >= 0 && end > start ? {start, end} : undefined;
+};
+
+const gap = (node: DOMElement, axis: 'column' | 'row'): number =>
+	axis === 'column'
+		? node.style.columnGap ?? node.style.gap ?? 0
+		: node.style.rowGap ?? node.style.gap ?? 0;
+
+const trackSizes = (tracks: Track[], available: number, trackGap: number, autoSizes: number[]): number[] => {
+	const minimum = tracks.reduce((total, track, index) => total +
+		(track.type === 'fixed' ? track.value : track.type === 'minmax' ? track.min : track.type === 'auto' ? (autoSizes[index] ?? 0) : 0), 0);
+	const free = Math.max(0, available - minimum - Math.max(0, tracks.length - 1) * trackGap);
+	const fractionTotal = tracks.reduce((total, track) => total + (track.type === 'fr' ? track.value : track.type === 'minmax' && track.max === 'fr' ? 1 : 0), 0);
+	return tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.value;
+		if (track.type === 'auto') return autoSizes[index] ?? 0;
+		if (track.type === 'minmax' && track.max !== 'fr') return Math.max(track.min, track.max);
+		const factor = track.type === 'fr' ? track.value : 1;
+		return (track.type === 'minmax' ? track.min : 0) + (fractionTotal ? free * factor / fractionTotal : 0);
+	});
+};
+
+const offsets = (sizes: number[], trackGap: number): number[] => {
+	let position = 0;
+	return sizes.map(size => {
+		const result = position;
+		position += size + trackGap;
+		return result;
+	});
+};
+
+const spanSize = (sizes: number[], start: number, end: number, trackGap: number): number =>
+	sizes.slice(start, end).reduce((total, size) => total + size, 0) + Math.max(0, end - start - 1) * trackGap;
+
+const layoutGrid = (node: DOMElement): void => {
+	if (node.style.display === 'grid' && node.yogaNode) {
+		const children = node.childNodes.filter((child): child is DOMElement => Boolean(child.yogaNode));
+		let columns = splitTracks(node.style.gridTemplateColumns);
+		if (columns.length === 0) columns = [{type: 'auto'}];
+		let rows = splitTracks(node.style.gridTemplateRows);
+		const placements: Array<{node: DOMElement; column: Placement; row: Placement}> = [];
+		let nextColumn = 0;
+		let nextRow = 0;
+		for (const child of children) {
+			const column = placement(child.style.gridColumn);
+			const row = placement(child.style.gridRow);
+			const resolvedColumn = column ?? {start: nextColumn, end: nextColumn + 1};
+			const resolvedRow = row ?? {start: nextRow, end: nextRow + 1};
+			placements.push({node: child, column: resolvedColumn, row: resolvedRow});
+			if (!column) {
+				nextColumn++;
+				if (nextColumn >= columns.length) { nextColumn = 0; nextRow++; }
+			}
+		}
+		const columnCount = Math.max(columns.length, ...placements.map(item => item.column.end));
+		while (columns.length < columnCount) columns.push({type: 'auto'});
+		const rowCount = Math.max(rows.length, 0, ...placements.map(item => item.row.end));
+		while (rows.length < rowCount) rows.push({type: 'auto'});
+		const columnGap = gap(node, 'column');
+		const rowGap = gap(node, 'row');
+		const contentWidth = node.yogaNode.getComputedWidth() - node.yogaNode.getComputedPadding(Yoga.EDGE_LEFT) - node.yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) - node.yogaNode.getComputedBorder(Yoga.EDGE_LEFT) - node.yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+		const contentHeight = node.yogaNode.getComputedHeight() - node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) - node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) - node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) - node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+		const columnAuto = columns.map((track, index) => track.type === 'auto' ? Math.max(0, ...placements.filter(item => item.column.start === index && item.column.end === index + 1).map(item => item.node.yogaNode!.getComputedWidth())) : 0);
+		const columnSizes = trackSizes(columns, contentWidth, columnGap, columnAuto);
+		const rowAuto = rows.map((track, index) => track.type === 'auto' ? Math.max(0, ...placements.filter(item => item.row.start === index && item.row.end === index + 1).map(item => item.node.yogaNode!.getComputedHeight())) : 0);
+		const rowSizes = trackSizes(rows, contentHeight, rowGap, rowAuto);
+		const columnOffsets = offsets(columnSizes, columnGap);
+		const rowOffsets = offsets(rowSizes, rowGap);
+		for (const item of placements) {
+			const child = item.node.yogaNode!;
+			child.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+			child.setPosition(Yoga.EDGE_LEFT, columnOffsets[item.column.start]!);
+			child.setPosition(Yoga.EDGE_TOP, rowOffsets[item.row.start]!);
+			child.setWidth(spanSize(columnSizes, item.column.start, item.column.end, columnGap));
+			child.setHeight(spanSize(rowSizes, item.row.start, item.row.end, rowGap));
+		}
+	}
+
+	for (const child of node.childNodes) {
+		if (child.yogaNode) layoutGrid(child as DOMElement);
+	}
+};
+
+export const calculateLayout = (root: DOMElement): void => {
+	for (let pass = 0; pass < 3; pass++) {
+		root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+		layoutGrid(root);
+	}
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+};
